    const undefinedResult = truncateContent(undefined, 80);
    expect(undefinedResult).toBe('');

    // empty string
    const emptyResult = truncateContent('', 80);
    expect(emptyResult).toBe('');
    
    // zero maxLength should return empty string regardless of content
    const zeroResult = truncateContent('some content', 0);
    expect(zeroResult).toBe('');
